/**
 * Adapter: UI and utility re-exports for copy-standalone portability.
 */
"use client";

export { cn } from "@/lib/utils";

"use client";

import {
  ToolUIErrorBoundary,
  type ToolUIErrorBoundaryProps,
} from "@/components/tool-ui/shared";

export function LinkPreviewErrorBoundary(
  props: Omit<ToolUIErrorBoundaryProps, "componentName">,
) {
  const { children, ...rest } = props;
  return (
    <ToolUIErrorBoundary componentName="LinkPreview" {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );
}

export { LinkPreview } from "./link-preview";
export type { LinkPreviewProps } from "./link-preview";
export { LinkPreviewErrorBoundary } from "./error-boundary";
export { SerializableLinkPreviewSchema, parseSerializableLinkPreview } from "./schema";
export type { SerializableLinkPreview } from "./schema";

/* eslint-disable @next/next/no-img-element */
"use client";

import * as React from "react";
import { Globe } from "lucide-react";
import { cn } from "./_adapter";
import { ActionButtons, normalizeActionsConfig, type ActionsProp } from "@/components/tool-ui/shared";
import { RATIO_CLASS_MAP, getFitClass, sanitizeHref } from "@/components/tool-ui/shared/media";
import type { SerializableLinkPreview } from "./schema";

const FALLBACK_LOCALE = "en-US";
const CONTENT_SPACING = "px-5 py-4 gap-2";

export interface LinkPreviewProps extends SerializableLinkPreview {
  className?: string;
  onNavigate?: (href: string, preview: SerializableLinkPreview) => void;
  responseActions?: ActionsProp;
  onResponseAction?: (actionId: string) => void | Promise<void>;
  onBeforeResponseAction?: (actionId: string) => boolean | Promise<boolean>;
}

export function LinkPreview(props: LinkPreviewProps) {
  const {
    className,
    onNavigate,
    responseActions,
    onResponseAction,
    onBeforeResponseAction,
    ...serializable
  } = props;

  const {
    id,
    href: rawHref,
    title,
    description,
    image,
    domain,
    favicon,
    ratio = "16:9",
    fit = "cover",
    locale: providedLocale,
  } = serializable;

  const locale = providedLocale ?? FALLBACK_LOCALE;
  const sanitizedHref = sanitizeHref(rawHref);

  const previewData: SerializableLinkPreview = {
    ...serializable,
    href: sanitizedHref ?? rawHref,
    locale,
  };

  const normalizedActions = React.useMemo(
    () => normalizeActionsConfig(responseActions),
    [responseActions],
  );

  const handleClick = () => {
    if (!sanitizedHref) return;
    if (onNavigate) {
      onNavigate(sanitizedHref, previewData);
    } else if (typeof window !== "undefined") {
      window.open(sanitizedHref, "_blank", "noopener,noreferrer");
    }
  };

  return (
    <article
      className={cn("relative w-full min-w-80 max-w-md", className)}
      lang={locale}
      data-tool-ui-id={id}
      data-slot="link-preview"
    >
      <div
        className={cn(
          "group @container relative isolate flex w-full min-w-0 flex-col overflow-hidden rounded-xl",
          "border border-border bg-card text-sm shadow-xs",
          sanitizedHref && "cursor-pointer",
        )}
        onClick={sanitizedHref ? handleClick : undefined}
        role={sanitizedHref ? "link" : undefined}
        tabIndex={sanitizedHref ? 0 : undefined}
        onKeyDown={
          sanitizedHref
            ? (e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  handleClick();
                }
              }
            : undefined
        }
      >
        <div className="flex flex-col">
          {image && (
            <div
              className={cn(
                "bg-muted relative w-full overflow-hidden",
                ratio !== "auto" ? RATIO_CLASS_MAP[ratio] : "aspect-[5/3]",
              )}
            >
              <img
                src={image}
                alt=""
                loading="lazy"
                decoding="async"
                className={cn(
                  "absolute inset-0 h-full w-full",
                  getFitClass(fit),
                  "object-center transition-transform duration-200 group-hover:scale-[1.01]",
                )}
              />
            </div>
          )}
          <div className={cn("flex flex-col", CONTENT_SPACING)}>
            {domain && (
              <div className="text-muted-foreground flex items-center gap-2 text-xs">
                {favicon ? (
                  <img
                    src={favicon}
                    alt=""
                    aria-hidden="true"
                    width={16}
                    height={16}
                    className="size-4 rounded-full object-cover"
                    loading="lazy"
                    decoding="async"
                  />
                ) : (
                  <div className="border-border/60 bg-muted flex size-4 shrink-0 items-center justify-center rounded-full border">
                    <Globe className="h-2.5 w-2.5" aria-hidden="true" />
                  </div>
                )}
                <span>{domain}</span>
              </div>
            )}
            {title && (
              <h3 className="text-foreground text-pretty text-base font-medium">
                <span className="line-clamp-2">{title}</span>
              </h3>
            )}
            {description && (
              <p className="text-muted-foreground text-pretty leading-snug">
                <span className="line-clamp-2">{description}</span>
              </p>
            )}
          </div>
        </div>
      </div>
      {normalizedActions && (
        <div className="@container/actions mt-3">
          <ActionButtons
            actions={normalizedActions.items}
            align={normalizedActions.align}
            confirmTimeout={normalizedActions.confirmTimeout}
            onAction={(actionId: string) => onResponseAction?.(actionId)}
            onBeforeAction={onBeforeResponseAction}
          />
        </div>
      )}
    </article>
  );
}

import { z } from "zod";
import {
  ToolUIIdSchema,
  ToolUIReceiptSchema,
  ToolUIRoleSchema,
  parseWithSchema,
} from "@/components/tool-ui/shared";
import { AspectRatioSchema, MediaFitSchema } from "@/components/tool-ui/shared/media";

export const SerializableLinkPreviewSchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  receipt: ToolUIReceiptSchema.optional(),
  href: z.url(),
  title: z.string().optional(),
  description: z.string().optional(),
  image: z.url().optional(),
  domain: z.string().optional(),
  favicon: z.url().optional(),
  ratio: AspectRatioSchema.optional(),
  fit: MediaFitSchema.optional(),
  createdAt: z.string().datetime().optional(),
  locale: z.string().optional(),
});

export type SerializableLinkPreview = z.infer<typeof SerializableLinkPreviewSchema>;

export function parseSerializableLinkPreview(input: unknown): SerializableLinkPreview {
  return parseWithSchema(SerializableLinkPreviewSchema, input, "LinkPreview");
}
